28	// newSpokeServer returns an httptest.Server that responds to /graphql with the
29	// given handler and exposes its base URL.
30	func newSpokeServer(t *testing.T, handler http.HandlerFunc) (*httptest.Server, SpokeRecord) {
31		t.Helper()
32		mux := http.NewServeMux()
33		mux.HandleFunc("/graphql", handler)
34		srv := httptest.NewServer(mux)
35		t.Cleanup(srv.Close)
36		return srv, SpokeRecord{
37			NodeID:        "node-" + srv.Listener.Addr().String(),
38			Name:          "spoke",
39			URL:           srv.URL,
40			DDxVersion:    "0.1.0",
41			SchemaVersion: CurrentSchemaVersion,
42			Status:        StatusActive,
43		}
44	}
