89		if err != nil {
90			t.Fatalf("execute: %v", err)
91		}
92		if _, ok := res.Responses[good.NodeID]; !ok {
93			t.Fatalf("expected good spoke to succeed, got %+v", res)
94		}
95		if _, ok := res.Errors[dead.NodeID]; !ok {
96			t.Fatalf("expected dead spoke to be in errors map, got %+v", res.Errors)
97		}
98		if status, ok := res.StatusUpdates[dead.NodeID]; !ok || status != StatusOffline {
99			t.Fatalf("expected dead spoke status update offline, got %+v", res.StatusUpdates)
100		}
101		// The good spoke must NOT receive a status update — only transport failures do.
102		if _, ok := res.StatusUpdates[good.NodeID]; ok {
103			t.Fatalf("good spoke should not receive a status update")
104		}
105	}
