159	func TestFanOut_MaxConcurrencyEnforced(t *testing.T) {
160		const totalSpokes = 10
161		const maxConc = 3
162	
163		var inFlight int32
164		var peak int32
165		gate := make(chan struct{})
166	
167		handler := func(w http.ResponseWriter, r *http.Request) {
168			cur := atomic.AddInt32(&inFlight, 1)
169			for {
170				p := atomic.LoadInt32(&peak)
171				if cur <= p || atomic.CompareAndSwapInt32(&peak, p, cur) {
172					break
173				}
174			}
175			<-gate
176			atomic.AddInt32(&inFlight, -1)
177			_, _ = w.Write(okGraphQLBody(t, map[string]any{"data": "ok"}))
178		}
179	
180		var spokes []SpokeRecord
181		for i := 0; i < totalSpokes; i++ {
182			_, s := newSpokeServer(t, handler)
183			s.NodeID = fmt.Sprintf("node-%d", i)
184			spokes = append(spokes, s)
185		}
186	
187		c := NewFanOutClient()
188		c.HubDDxVersion = "0.1.0"
189		c.HubSchemaVersion = CurrentSchemaVersion
190		c.MaxConcurrency = maxConc
191		c.PerNodeTimeout = 5 * time.Second
192	
193		done := make(chan *FanOutResult, 1)
194		go func() {
195			res, _ := c.Execute(context.Background(), spokes, &FanOutRequest{Query: "{ __typename }"})
196			done <- res
197		}()
198	
199		// Give all goroutines time to spin up and observe peak concurrency.
200		deadline := time.Now().Add(2 * time.Second)
201		for time.Now().Before(deadline) {
202			if atomic.LoadInt32(&peak) >= int32(maxConc) {
203				break
204			}
205			time.Sleep(10 * time.Millisecond)
206		}
207		// Briefly observe steady-state peak before releasing.
208		time.Sleep(50 * time.Millisecond)
209		if got := atomic.LoadInt32(&peak); got > int32(maxConc) {
210			t.Fatalf("peak in-flight %d exceeded max-concurrency %d", got, maxConc)
211		}
212		close(gate)
213	
214		res := <-done
215		if len(res.Responses) != totalSpokes {
216			t.Fatalf("want %d successes, got %d", totalSpokes, len(res.Responses))
217		}
218		if got := atomic.LoadInt32(&peak); got > int32(maxConc) {
219			t.Fatalf("peak in-flight %d exceeded max-concurrency %d", got, maxConc)
220		}
221		if got := atomic.LoadInt32(&peak); got == 0 {
222			t.Fatalf("peak in-flight is zero — handler never observed concurrency")
223		}
224	}
