226	func TestFanOut_VersionIncompatibleSpokesSkipped(t *testing.T) {
227		var hits int32
228		_, compat := newSpokeServer(t, func(w http.ResponseWriter, r *http.Request) {
229			atomic.AddInt32(&hits, 1)
230			_, _ = w.Write(okGraphQLBody(t, map[string]any{"data": "ok"}))
231		})
232		_, incompat := newSpokeServer(t, func(w http.ResponseWriter, r *http.Request) {
233			atomic.AddInt32(&hits, 1)
234			_, _ = w.Write(okGraphQLBody(t, map[string]any{"data": "ok"}))
235		})
236		incompat.NodeID = "incompat-spoke"
237		incompat.DDxVersion = "9.0.0" // major mismatch
238	
239		var logs []string
240		var logMu sync.Mutex
241		c := NewFanOutClient()
242		c.HubDDxVersion = "0.1.0"
243		c.HubSchemaVersion = CurrentSchemaVersion
244		c.Logger = func(format string, args ...any) {
245			logMu.Lock()
246			logs = append(logs, fmt.Sprintf(format, args...))
247			logMu.Unlock()
248		}
249	
250		res, err := c.Execute(context.Background(), []SpokeRecord{compat, incompat}, &FanOutRequest{Query: "{ __typename }"})
251		if err != nil {
252			t.Fatalf("execute: %v", err)
253		}
254		if got := atomic.LoadInt32(&hits); got != 1 {
255			t.Fatalf("expected exactly one HTTP hit (compat only); got %d", got)
256		}
257		reason, ok := res.Skipped[incompat.NodeID]
258		if !ok || reason != SkipReasonIncompatibleVersion {
259			t.Fatalf("expected incompat spoke to be skipped with %q, got %+v", SkipReasonIncompatibleVersion, res.Skipped)
260		}
261		if _, ok := res.Errors[incompat.NodeID]; ok {
262			t.Fatalf("skipped spoke must not appear in Errors map")
263		}
264		logMu.Lock()
265		defer logMu.Unlock()
266		var sawSkipLog bool
267		for _, l := range logs {
268			if strings.Contains(l, incompat.NodeID) && strings.Contains(l, string(SkipReasonIncompatibleVersion)) {
269				sawSkipLog = true
270			}
271		}
272		if !sawSkipLog {
273			t.Fatalf("expected a skip log entry for %q; logs=%v", incompat.NodeID, logs)
274		}
275	}
