394	func TestFanOut_HTTPErrorIsNotOffline(t *testing.T) {
395		_, errSpoke := newSpokeServer(t, func(w http.ResponseWriter, r *http.Request) {
396			http.Error(w, "boom", http.StatusInternalServerError)
397		})
398	
399		c := NewFanOutClient()
400		c.HubDDxVersion = "0.1.0"
401		c.HubSchemaVersion = CurrentSchemaVersion
402	
403		res, err := c.Execute(context.Background(), []SpokeRecord{errSpoke}, &FanOutRequest{Query: "{ __typename }"})
404		if err != nil {
405			t.Fatalf("execute: %v", err)
406		}
407		if _, ok := res.Errors[errSpoke.NodeID]; !ok {
408			t.Fatalf("expected an error for 500 response")
409		}
410		// HTTP error must NOT mark the spoke offline (transport worked).
411		if _, ok := res.StatusUpdates[errSpoke.NodeID]; ok {
412			t.Fatalf("HTTP error must not produce a status update; got %+v", res.StatusUpdates)
413		}
414		var found bool
415		for _, n := range res.Nodes {
416			if n.NodeID == errSpoke.NodeID && n.Outcome == OutcomeHTTPError {
417				found = true
418				if n.HTTPStatus != http.StatusInternalServerError {
419					t.Fatalf("HTTPStatus = %d, want 500", n.HTTPStatus)
420				}
421			}
422		}
423		if !found {
424			t.Fatalf("expected OutcomeHTTPError for spoke, got %+v", res.Nodes)
425		}
426	}
