438	func TestFanOut_PostsGraphQLPayload(t *testing.T) {
439		var got struct {
440			Query         string         `json:"query"`
441			OperationName string         `json:"operationName"`
442			Variables     map[string]any `json:"variables"`
443		}
444		_, s := newSpokeServer(t, func(w http.ResponseWriter, r *http.Request) {
445			if r.Method != http.MethodPost {
446				t.Errorf("method = %s, want POST", r.Method)
447			}
448			if ct := r.Header.Get("Content-Type"); ct != "application/json" {
449				t.Errorf("Content-Type = %q, want application/json", ct)
450			}
451			if err := json.NewDecoder(r.Body).Decode(&got); err != nil {
452				t.Errorf("decode body: %v", err)
453			}
454			_, _ = w.Write(okGraphQLBody(t, map[string]any{"data": "ok"}))
455		})
456	
457		c := NewFanOutClient()
458		c.HubDDxVersion = "0.1.0"
459		c.HubSchemaVersion = CurrentSchemaVersion
460		_, err := c.Execute(context.Background(), []SpokeRecord{s}, &FanOutRequest{
461			Query:         "query Q { x }",
462			OperationName: "Q",
463			Variables:     map[string]any{"foo": "bar"},
464		})
